import { useContext, useState, useEffect, useRef } from "react";
import { ThemeContext } from "../context/ThemeContext";

function generateUserName() {
    const suffix = Math.floor(1000 + Math.random() * 9000);
    return `User_${suffix}`;
}

export default function TopBar({ user, setUser }) {
    const { theme, toggleTheme } = useContext(ThemeContext);
    const [menuOpen, setMenuOpen] = useState(false);
    const wrapperRef = useRef(null);

    const handleMockLogin = () => {
        setUser({
            id: Date.now(),
            name: generateUserName(),
            email: "guest@chat.ai"
        });
    };

    const handleLogout = () => {
        setUser(null);
        setMenuOpen(false);
    };

    // Close dropdown if clicking outside
    useEffect(() => {
        const handleClickOutside = (event) => {
            if (wrapperRef.current && !wrapperRef.current.contains(event.target)) {
                setMenuOpen(false);
            }
        };
        document.addEventListener("click", handleClickOutside);
        return () => {
            document.removeEventListener("click", handleClickOutside);
        };
    }, []);

    return (
        <header className="topbar">
            <div className="topbar-left">
                <h1 className="title">Vyom's AI Chatbot</h1>
            </div>

            <div className="topbar-right">
                <button className="icon" onClick={toggleTheme}>
                    {theme === "dark" ? "☀️" : "🌙"}
                </button>

                {!user ? (
                    <button className="login" onClick={handleMockLogin}>
                        Login
                    </button>
                ) : (
                    <div
                        className={`user-wrapper ${menuOpen ? "open" : ""}`}
                        ref={wrapperRef}
                        onClick={() => setMenuOpen(prev => !prev)} // Toggle dropdown
                    >
                        <div className="user-info">
                            <div className="avatar">👤</div>
                            <span className="username">{user.name}</span>

                            <svg
                                width="10"
                                height="10"
                                viewBox="0 0 24 24"
                                className="caret-icon"
                            >
                                <path
                                    d="M6 9L12 15L18 9"
                                    fill="none"
                                    stroke="currentColor"
                                    strokeWidth="2"
                                    strokeLinecap="round"
                                    strokeLinejoin="round"
                                />
                            </svg>
                        </div>

                        {menuOpen && (
                            <div className="dropdown">
                                <button onClick={handleLogout}>Logout</button>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </header>
    );
}
